example.query:
-- 1. Finding a missing login day for a user
SELECT l1.login_day + 1 AS missing_day FROM Logins AS l1
WHERE l1.user_id = 1 AND NOT EXISTS (
  SELECT 1 FROM Logins AS l2 WHERE l2.user_id = 1 AND l2.login_day = l1.login_day + 1
) AND l1.login_day < (SELECT MAX(login_day) FROM Logins WHERE user_id = 1);

-- 2. Grouping login days into consecutive islands
SELECT user_id, login_day, login_day - ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY login_day) AS grp
FROM Logins WHERE user_id = 1;

shared_table.create_sql:
CREATE TABLE Logins (
  id INTEGER PRIMARY KEY,
  user_id INTEGER,
  login_day INTEGER
);
